const assert = require('assert');
const fs = require('fs');
const vm = require('vm');
const path = require('path');

// Load and evaluate the translated parser code in a VM context
const code = fs.readFileSync(path.join(__dirname, 'translated.js'), 'utf8');
const context = { require, console, RegExp, Set, Array, Object };
vm.createContext(context);
vm.runInContext(code, context);

const ParserBase = context.ParserBase;

function testStandardSection() {
    const raw = '<![temp]]>xyz';
    const parser = ParserBase();
    parser.rawdata = raw;
    const res = parser.parse_marked_section(0, false);
    assert.strictEqual(res, raw.indexOf(']]>') + 3);
}

function testUnknownSection() {
    const raw = '<![unknown]]>';
    const parser = ParserBase();
    parser.rawdata = raw;
    let threw = false;
    try {
        parser.parse_marked_section(0, false);
    } catch (e) {
        threw = true;
    }
    assert.strictEqual(threw, true);
}

function testNoClosing() {
    const raw = '<![temp';
    const parser = ParserBase();
    parser.rawdata = raw;
    const res = parser.parse_marked_section(0, false);
    assert.strictEqual(res, -1);
}

function testReport() {
    const raw = '<![temp]]>';
    const parser = ParserBase();
    parser.rawdata = raw;
    const calls = [];
    parser.unknown_decl = function(data) { calls.push(data); };
    const res = parser.parse_marked_section(0, true);
    assert.strictEqual(res, raw.indexOf(']]>') + 3);
    assert.strictEqual(calls.length, 1);
    assert.strictEqual(calls[0], raw.substring(3, raw.indexOf(']]>')));
}

function runTests() {
    testStandardSection();
    testUnknownSection();
    testNoClosing();
    testReport();
    console.log('All tests passed');
}

runTests();

