import unittest
from python.source import MyHTMLParserTester, listener_event_list

class TestParseStartTag(unittest.TestCase):
    def setUp(self):
        listener_event_list.clear()

    def test_simple_tag(self):
        p = MyHTMLParserTester(True)
        p.rawdata = "<div>"
        end = p.parse_starttag(0)
        self.assertEqual(end, 5)
        self.assertEqual(p.get_starttag_text(), "<div>")
        self.assertEqual(listener_event_list, [("starttag", "div", [])])

    def test_tag_with_attributes(self):
        p = MyHTMLParserTester(True)
        html = "<a href=https://example.com title='Example'>"
        p.rawdata = html
        end = p.parse_starttag(0)
        self.assertEqual(end, len(html))
        self.assertEqual(p.get_starttag_text(), html)
        self.assertEqual(listener_event_list, [
            ("starttag", "a", [("href", "https://example.com"), ("title", "Example")])
        ])

    def test_self_closing_tag(self):
        p = MyHTMLParserTester(True)
        html = "<img src=foo.png alt=bar/>"
        p.rawdata = html
        end = p.parse_starttag(0)
        self.assertEqual(end, len(html))
        self.assertEqual(p.get_starttag_text(), html)
        # self-closing sets lasttag and calls handle_startendtag
        self.assertEqual(p.lasttag, "img")

if __name__ == '__main__':
    unittest.main()

