const assert = require('assert');
const { MyHTMLParserTester, listener_event_list } = require('./translated');

function clear() {
    listener_event_list.length = 0;
}

function testSimpleTag() {
    clear();
    const p = MyHTMLParserTester(true);
    p.rawdata = '<div>';
    const end = p.parse_starttag(0);
    assert.strictEqual(end, 5);
    assert.strictEqual(p.get_starttag_text(), '<div>');
    assert.deepStrictEqual(listener_event_list, [['starttag', 'div', []]]);
}

function testTagWithAttributes() {
    clear();
    const p = MyHTMLParserTester(true);
    const html = "<a href=https://example.com title='Example'>";
    p.rawdata = html;
    const end = p.parse_starttag(0);
    assert.strictEqual(end, html.length);
    assert.strictEqual(p.get_starttag_text(), html);
    assert.deepStrictEqual(listener_event_list, [
        ['starttag', 'a', [['href', 'https://example.com'], ['title', 'Example']]]
    ]);
}

function testSelfClosingTag() {
    clear();
    const p = MyHTMLParserTester(true);
    const html = '<img src=foo.png alt=bar/>';
    p.rawdata = html;
    const end = p.parse_starttag(0);
    assert.strictEqual(end, html.length);
    assert.strictEqual(p.get_starttag_text(), html);
    assert.strictEqual(p.lasttag, 'img');
}

function run() {
    testSimpleTag();
    testTagWithAttributes();
    testSelfClosingTag();
    console.log('All tests passed');
}

run();

