    var endpos = class_var.check_for_whole_start_tag(i);
    if (endpos < 0) {
        return endpos;
    }
    var rawdata = class_var.rawdata;
    class_var.__starttag_text = rawdata.substring(i, endpos);
    // Now parse the data between i+1 and endpos into a tag and attrs
    var attrs = [];
    var match = tagfind_tolerant.exec(rawdata.substring(i + 1));
    if (!match) {
        throw new Error('unexpected call to parse_starttag()');
    }
    class_var.lasttag = tag = match[1].toLowerCase();
    var k0 = match.index + match[0].length + i + 1;
    // extract tail including attributes and closing
    var tail = rawdata.substring(k0, endpos).trim();
    // remove closing '>' or '/>'
    var attrString = tail;
    if (tail.endsWith('/>')) {
        attrString = tail.slice(0, -2).trim();
    } else if (tail.endsWith('>')) {
        attrString = tail.slice(0, -1).trim();
    }
    if (attrString) {
        var parts = attrString.split(/\s+/);
        for (var pi = 0; pi < parts.length; pi++) {
            var part = parts[pi];
            if (!part) continue;
            var eq = part.indexOf('=');
            var name = part;
            var value = null;
            if (eq >= 0) {
                name = part.slice(0, eq);
                value = part.slice(eq + 1);
                if ((value[0] === '"' && value[value.length - 1] === '"') ||
                    (value[0] === "'" && value[value.length - 1] === "'")) {
                    value = value.slice(1, -1);
                }
                value = unescape(value);
            }
            attrs.push([name.toLowerCase(), value]);
        }
    }
    // determine closing sequence
    var end = (rawdata[endpos - 2] === '/' ? '/>' : '>');
    if (end !== '>' && end !== '/>') {
        class_var.handle_data(rawdata.substring(i, endpos));
        return endpos;
    }
    if (end === '/>') {
        class_var.handle_startendtag(tag, attrs);
    } else {
        class_var.handle_starttag(tag, attrs);
        if (class_var.CDATA_CONTENT_ELEMENTS.includes(tag)) {
            class_var.set_cdata_mode(tag);
        }
    }
    return endpos;
}
